#include <stdio.h>
#include <stdlib.h>
int main(){
    int T; if(scanf("%d", &T)!=1) return 0;
    while(T--){
        int N; scanf("%d", &N);
        int *a = (int*)malloc(N * sizeof(int));
        for(int i=0;i<N;i++) scanf("%d", &a[i]);
        int *tails = (int*)malloc(N * sizeof(int));
        int len = 0;
        for(int i=0;i<N;i++){
            int x = a[i];
            int l = 0, r = len;
            while(l < r){
                int m = (l + r) / 2;
                if(tails[m] > x) r = m; else l = m + 1;
            }
            tails[l] = x;
            if(l == len) len++;
        }
        printf("%d\n", len);
        free(a);
        free(tails);
    }
    return 0;
}

