        vector<int> tails;
        tails.reserve(N);
        for(int x: a){
            auto it = upper_bound(tails.begin(), tails.end(), x);
            if(it==tails.end()) tails.push_back(x);
            else *it = x;
        }
        cout << tails.size() << '\n';
