import sys, bisect

def solve():
    data = sys.stdin.read().strip().split()
    if not data:
        return
    it = iter(data)
    T = int(next(it))
    out_lines = []
    for _ in range(T):
        N = int(next(it))
        tails = []
        for _ in range(N):
            x = int(next(it))
            idx = bisect.bisect_right(tails, x)
            if idx == len(tails):
                tails.append(x)
            else:
                tails[idx] = x
        out_lines.append(str(len(tails)))
    sys.stdout.write('\n'.join(out_lines))

if __name__ == "__main__":
    solve()

